@@ -0,0 +1,26 @@
+import { FILE_CHUNK_SIZE } from '@proton/shared/lib/drive/constants';
+
+import { mockGlobalFile, testFile } from '../../../utils/test/file';
+import { createFileExtendedAttributes } from '../extendedAttributes';
+
+describe('extended attrbiutes block sizes', () => {
+    beforeEach(() => {
+        mockGlobalFile();
+    });
+
+    it('test execution', () => {
+        const testCases: [File, number[]][] = [
+            [testFile('empty.txt', 0), []],
+            [testFile('exact.bin', FILE_CHUNK_SIZE * 2), [FILE_CHUNK_SIZE, FILE_CHUNK_SIZE]],
+            [testFile('remainder.bin', FILE_CHUNK_SIZE * 2 + 123), [FILE_CHUNK_SIZE, FILE_CHUNK_SIZE, 123]],
+        ];
+
+        testCases.forEach(([file, expectedBlockSizes]) => {
+            const xattrs = createFileExtendedAttributes({
+                file,
+            });
+
+            expect(xattrs.Common.BlockSizes).toEqual(expectedBlockSizes);
+        });
+    });
+});
diff --git a/applications/drive/src/app/store/_links/test/extendedAttributes.compatibility.test.ts b/applications/drive/src/app/store/_links/test/extendedAttributes.compatibility.test.ts
