@@ -0,0 +1,37 @@
+import { mockGlobalFile, testFile } from '../../../utils/test/file';
+import { createFileExtendedAttributes } from '../extendedAttributes';
+
+describe('extended attrbiutes compatibility metadata', () => {
+    beforeEach(() => {
+        mockGlobalFile();
+    });
+
+    it('test execution', () => {
+        const xattrsWithDigests = createFileExtendedAttributes({
+            file: testFile('testfile.txt', 123),
+            digests: { sha1: 'abcdef' },
+            media: { width: 100, height: 200 },
+        });
+
+        expect(xattrsWithDigests).toStrictEqual({
+            Common: {
+                Version: 2,
+                ModificationTime: '2009-02-13T23:31:30.000Z',
+                Size: 123,
+                BlockSizes: [123],
+                Digests: {
+                    SHA1: 'abcdef',
+                },
+            },
+            Media: {
+                Width: 100,
+                Height: 200,
+            },
+        });
+
+        const xattrsWithoutDigests = createFileExtendedAttributes({
+            file: testFile('nodigest.txt', 5),
+        });
+        expect(xattrsWithoutDigests.Common.Digests).toBeUndefined();
+    });
+});
diff --git a/applications/drive/src/app/store/_links/test/extendedAttributes.modificationTime.test.ts b/applications/drive/src/app/store/_links/test/extendedAttributes.modificationTime.test.ts
