+++ b/applications/drive/src/app/store/_links/test/extendedAttributes.modificationTime.test.ts
@@ -0,0 +1,34 @@
+import { mockGlobalFile, testFile } from '../../../utils/test/file';
+import { createFileExtendedAttributes, parseExtendedAttributes } from '../extendedAttributes';
+
+describe('extended attrbiutes modification time', () => {
+    beforeEach(() => {
+        mockGlobalFile();
+    });
+
+    it('test execution', () => {
+        const created = createFileExtendedAttributes({
+            file: testFile('testfile.txt', 123),
+        });
+        expect(created.Common.ModificationTime).toBe('2009-02-13T23:31:30.000Z');
+
+        const parsed = parseExtendedAttributes('{"Common": {"ModificationTime": "2009-02-13T23:31:30+0000"}}');
+        expect(parsed.Common.ModificationTime).toBe(1234567890000);
+
+        expect(() => parseExtendedAttributes('')).not.toThrow();
+        expect(() => parseExtendedAttributes('not-json')).not.toThrow();
+
+        const parsedInvalid = parseExtendedAttributes(
+            '{"Common":{"ModificationTime":"bad-date","Size":"aaa","BlockSizes":"aaa","Digests":{"SHA1":12}},"Media":{"Width":"100"}}'
+        );
+        expect(parsedInvalid.Common.ModificationTime).toBeUndefined();
+        expect(parsedInvalid.Common.Size).toBeUndefined();
+        expect(parsedInvalid.Common.BlockSizes).toBeUndefined();
+        expect(parsedInvalid.Common.Digests).toBeUndefined();
+        expect(parsedInvalid.Media).toBeUndefined();
+
+        const parsedPartial = parseExtendedAttributes('{"Common":{"Size":123}}');
+        expect(parsedPartial.Common.ModificationTime).toBeUndefined();
+        expect(parsedPartial.Common.Size).toBe(123);
+    });
+});
